+
+  const handleConnect = async () => {
+    if (!selectedOrg || !selectedUser) {
+      setError("Please select both organization and user");
+      return;
+    }
+
+    setLoading(true);
+    setError(null);
+
+    try {
+      const response = await fetch("http://localhost:8080/connect", {
+        method: "POST",
